import { Autumn } from 'autumn-js';
import fs from 'fs/promises';

const autumn = new Autumn({ apiKey: process.env.AUTUMN_SECRET_KEY });

async function main() {
  try {
    // 1. Create/sync customers in parallel
    const customersToCreate = [
      { id: 'user_test_001', name: 'Bob Builder', email: 'bob@example.com' },
      { id: 'user_test_002', name: 'Carol Coder', email: 'carol@example.com' }
    ];

    await Promise.all(
      customersToCreate.map(c => autumn.customers.getOrCreate({
        customerId: c.id,
        name: c.name,
        email: c.email
      }))
    );

    // 2. Attach the plan "free" to both in parallel
    await Promise.all(
      customersToCreate.map(async (c) => {
        try {
          await autumn.billing.attach({
            customerId: c.id,
            planId: 'free'
          });
        } catch (err) {
          if (err.statusCode === 400 && err.body && err.body.includes('is the same as the product being attached')) {
            console.log(`Plan 'free' is already attached to ${c.id}.`);
          } else {
            throw err;
          }
        }
      })
    );

    // 3. Save results
    const result = {
      customers: customersToCreate.map(c => ({
        customerId: c.id,
        planAttached: true
      }))
    };

    await fs.writeFile('/home/user/myproject/onboard_result.json', JSON.stringify(result, null, 2));
    console.log('Successfully onboarded customers and attached plan.');
  } catch (error) {
    console.error('Error onboarding customers:', error);
    process.exit(1);
  }
}

